class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        const int MOD = 1e9 + 7;
        vector<long long> dp(n + 1, 0);
        dp[1] = 1;
        long long total = 0, newlyInfected = 0;
        for (int i = 2; i <= n; ++i) {
            newlyInfected = (newlyInfected + dp[i - delay] - dp[i - forget] + MOD) % MOD;
            dp[i] = newlyInfected;
            total = (total + dp[i]) % MOD;
        }
        return total;
    }
};
efficiency: HIGH
time complexity: O(N)
space complexity: O(N)
energy implications: LOW
explanation: Utilizes dynamic programming to track the number of people who know the secret on each day, efficiently calculating the total number of people aware of the secret at the end of day n.
